let state = null;

export function initialize(wrapper, dotNetRef, timeoutMs) {
    const activityEvents = ["mousemove", "keydown", "click", "scroll", "touchstart"];
    let timerId = null;
    let isIdle = false;

    function resetTimer() {
        if (timerId !== null) {
            clearTimeout(timerId);
        }

        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync("OnUserActive");
        }

        timerId = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync("OnUserIdle");
        }, timeoutMs);
    }

    function onActivity() {
        resetTimer();
    }

    for (const evt of activityEvents) {
        wrapper.addEventListener(evt, onActivity, { passive: true });
    }

    // Start the initial timer
    resetTimer();

    state = { wrapper, activityEvents, onActivity, timerId: () => timerId, clearTimer: () => clearTimeout(timerId) };
}

export function dispose() {
    if (!state) return;

    const { wrapper, activityEvents, onActivity, clearTimer } = state;

    for (const evt of activityEvents) {
        wrapper.removeEventListener(evt, onActivity);
    }

    clearTimer();
    state = null;
}

